// Tomamos la fecha de inicio desde el input
const fechaInicioTexto = $('When Executed by Another Workflow').first().json.Fecha; // Ej: "2025-12-01T17:30:00"
const duracionMinutos = Number($('When Executed by Another Workflow').first().json.Duracion); // Ej: "30" -> 30

// Convertir a Date
const fechaInicio = new Date(fechaInicioTexto);

// Crear fecha fin sumando los minutos
const fechaFin = new Date(fechaInicio.getTime() + duracionMinutos * 60000);

// Formatear ambas a 'YYYY-MM-DDTHH:mm:ss'
function formatear(fecha) {
  return fecha.toISOString().substring(0, 19);
}

return [
  {
    json: {
      FechaInicio: formatear(fechaInicio),
      FechaFin: formatear(fechaFin),
    }
  }
];

let summary;
let telefono;

// Obtener datos
try {
  summary = $input.first().json.summary;
} catch {
  summary = undefined;
}

try {
  telefono = $('When Executed by Another Workflow')?.first()?.json?.Telefono;
} catch {
  telefono = undefined;
}


// ----------------------------
// EXTRAER NUMERO
// ----------------------------
function extraerNumero(valor) {

  if (!valor) return null;

  const texto = String(valor);

  // formato whatsapp jid
  let match = texto.match(/(\d+)@s\.whatsapp\.net/);
  if (match) return match[1];

  // numero plano (+54, 549, etc)
  const digits = texto.replace(/\D/g, "");
  if (digits.length >= 8) return digits;

  return null;
}


// ----------------------------
// NUMEROS DETECTADOS
// ----------------------------
const numeroSummary = extraerNumero(summary);
const numeroTelefono = extraerNumero(telefono);


// ----------------------------
// LOGICA FINAL
// ----------------------------

// ✅ Si alguno tiene numero → validar coincidencia
if (numeroSummary !== null || numeroTelefono !== null) {

  if (numeroSummary === null || numeroTelefono === null) {
    return [{ json: { coincide: false } }];
  }

  return [{
    json: {
      coincide: numeroSummary === numeroTelefono
    }
  }];
}

// ✅ Ninguno tiene numero → permitir
return [{
  json: {
    coincide: true
  }
}];

