const texto = $('Traer_citas').first().json.summary || "";

// buscar numero tipo 5492616763104@s.whatsapp.net
const match = texto.match(/(\d+)@s\.whatsapp\.net/);

if (!match) {
  return [
    {
      json: {
        existe: false,
        mensaje: "El numero no existe"
      }
    }
  ];
}

const numero = match[1];

// validar numero internacional (8 a 15 digitos)
const numeroValido = /^\d{8,15}$/.test(numero);

if (!numeroValido) {
  return [
    {
      json: {
        existe: false,
        mensaje: "El numero no es valido",
        numero: numero
      }
    }
  ];
}

// valido
return [
  {
    json: {
      existe: true,
      mensaje: "Numero valido",
      numero: numero
    }
  }
];

